cle")                            .font(.title)                    }                }                .padding()                .background(Color(.systemBackground).opacity(0.95))                                // The scrollable folder (and list) content.                ScrollView {                    VStack(alignment: .leading, spacing: 10) {                        ForEach(getTopLevelFolders()) { folder in                            FolderListView(folder: folder, userModel: userModel, globalExpanded: $globalExpanded)                        }                    }                    .padding()                }            }            .navigationBarHidden(true)        }    }}struct FolderListView: View {    let folder: OTDFolder    let userModel: OTDUserModel    @Binding var globalExpanded: Bool    @State private var isExpanded: Bool = true    var body: some View {        DisclosureGroup(isExpanded: $isExpanded) {            // Render the lists that belong to this folder.            ForEach(userModel.getMetasInFolder(for: folder)) { meta in                // Tapping a list navigates to the EditListView.                NavigationLink(destination: EditListView(listModel: OTDListModel(metadata: meta), isPresented: .constant(true)).environmentObject(userModel)) {                    Text(meta.title)                        .padding(.vertical, 4)                }            }            // Recursively render any subfolders.            ForEach(subfolders(for: folder)) { subfolder in                FolderListView(folder: subfolder, userModel: userModel, globalExpanded: $globalExpanded)                    .padding(.leading, 16)            }        } label: {            Text(folder.name)                .font(.headline)        }        .onChange(of: globalExpanded) { newValue in            // Update each folder’s expansion when the global toggle changes.            isExpanded = newValue        }    }        /// Finds all folders that are children of the given folder.    func subfolders(for folder: OTDFolder) -> [OTDFolder] {        guard let allFolders = userModel.currentUser?.folders else { return [] }        // A folder is a child if its ID is included in the parent’s folders array.        return allFolders.filter { folder.folders.contains($0.id) }    }}struct DropdownMenuDisclosureGroup: View {  @State private var isExpanded: Bool = false  var folderName: String  var listMetadatas: [OTDListMetadata]  var body: some View {      DisclosureGroup(folderName, isExpanded: $isExpanded) {      VStack {        ForEach(listMetadatas) { meta in            Text(meta.title)            .padding()            .onTapGesture {              isExpanded = false            }        }      }    }    .padding()    .background(Color.gray.opacity(0.1))    .cornerRadius(8)  }}